module median_filter (
    input obf_a,
    input b,
    input c,
    output reg median
);
    always @(*) begin
        if ((obf_a >= b && obf_a <= c) || (obf_a <= b && obf_a >= c))
            median = obf_a;
        else if ((b >= obf_a && b <= c) || (b <= obf_a && b >= c))
            median = b;
        else
            median = c;
    end
endmodule
